import scala.sys.process._
import scala.io.StdIn

object ShellService {
   def executeCommand(command: String): String = {
      try {
         val output = s"${command}".!!
         println("Command executed successfully")
         return output
      } catch {
         case e: Throwable => {
            println(s"An error occurred while executing the command: ${e.getMessage}")
            throw new Exception(s"Error while running shell command: $command", e)
         }
      }
   }
   
   def main(args: Array[String]): Unit = {
       // Accepting command from input 
